import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as n,d as a}from"./app-8955ab6e.js";const o={},l=a(`<h1 id="进程管理命令" tabindex="-1"><a class="header-anchor" href="#进程管理命令" aria-hidden="true">#</a> 进程管理命令</h1><h2 id="ps" tabindex="-1"><a class="header-anchor" href="#ps" aria-hidden="true">#</a> ps</h2><p>​<code>ps</code>​ 命令用于显示当前正在运行的进程（进程状态）信息。它是一个常用的 Linux 命令，可以监视系统上正在运行的进程，查找特定进程，以及获取关于进程资源使用情况的信息。</p><p>基本语法格式如下：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ps</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>其中，<code>options</code>​ 是一系列用于指定 <code>ps</code>​ 命令行为的选项。下面是一些常用的 <code>ps</code>​ 命令选项及其说明：</p><ul><li>​<code>-e</code>​: 显示所有所有进程，包括正在运行的和已经终止的，无论它们<strong>是否在当前终端会话</strong>中。</li><li>​<code>-a</code>​：显示<strong>当前终端会话</strong>中的所有用户进程，包括其他用户的进程，但默认情况下不包括停止的进程。</li><li>​<code>-x</code>​ 参数用于显示所有与当前用户相关的进程，包括没有终端控制的进程。它会列出不与任何终端相关联的进程，例如守护进程（daemon processes）等。</li><li>​<code>-f</code>​: 显示详细的进程信息，包括用户、PID、PPID、CPU 使用率、内存使用等。</li><li>​<code>-H</code>​: 显示进程树，以缩进方式显示进程之间的层次关系。可以更清晰地展示父进程和子进程的关系。</li><li>​<code>-L</code>​：显示进程的线程信息，如果一个进程有多个线程，这将显示每个线程的信息。</li><li>​<code>-u &lt;user&gt;</code>​: 显示指定用户的进程，可以同时指定多个用户，用逗号分隔</li><li>​<code>-p &lt;PID&gt;</code>​：显示指定进程ID的详细信息，可以添加多个进程ID，用空格分隔</li><li>​<code>--sort</code>​: 按指定的字段排序显示进程列表，例如 <code>--sort=-%cpu</code>​ 按 CPU 使用率降序排序。</li></ul><p>以下是一些常用的 <code>ps</code>​ 命令选项以及案例说明：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 显示当前终端窗口中的进程列表</span>
<span class="token function">ps</span>

<span class="token comment"># 显示所有进程，包括正在运行的和已经终止的</span>
<span class="token function">ps</span> <span class="token parameter variable">-e</span>

<span class="token comment"># 显示所有进程的详细信息，包括用户、PID（进程标识符）、CPU 使用率、内存使用等。</span>
<span class="token function">ps</span> <span class="token parameter variable">-ef</span>
<span class="token function">ps</span> <span class="token parameter variable">-aux</span>

<span class="token comment"># 显示特定用户运行的进程列表</span>
<span class="token function">ps</span> <span class="token parameter variable">-u</span> <span class="token operator">&lt;</span>用户名<span class="token operator">&gt;</span>
<span class="token comment"># 显示特定进程ID的详细信息</span>
<span class="token function">ps</span> <span class="token parameter variable">-p</span> <span class="token operator">&lt;</span>进程ID<span class="token operator">&gt;</span>

<span class="token comment"># 按照 CPU 使用率从高到低的顺序显示进程列表</span>
<span class="token function">ps</span> <span class="token parameter variable">-ef</span> <span class="token parameter variable">--sort</span><span class="token operator">=</span>-%cpu
<span class="token comment"># 按照内存使用率从高到低的顺序显示进程列表</span>
<span class="token function">ps</span> <span class="token parameter variable">-ef</span> <span class="token parameter variable">--sort</span><span class="token operator">=</span>-%mem

<span class="token comment"># 显示进程树，包括父进程和子进程的关系</span>
<span class="token function">ps</span> <span class="token parameter variable">-efH</span>
<span class="token comment"># 显示进程和线程，包括每个线程的详细信息</span>
<span class="token function">ps</span> <span class="token parameter variable">-efL</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="kill" tabindex="-1"><a class="header-anchor" href="#kill" aria-hidden="true">#</a> kill</h2><p><code>kill</code>​ 命令用于向进程发送信号，从而影响进程的行为。信号是一种通知机制，可以用来控制进程的运行状态、执行特定操作或请求进程终止。通过 <code>kill</code>​ 命令，您可以与正在运行的进程进行交互，例如终止、重新加载配置或重新启动等操作。</p><p>基本语法格式如下：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">kill</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token operator">&lt;</span>PID<span class="token operator">&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>其中，<code>&lt;PID&gt;</code>​ 是要操作的进程的进程ID。可以添加多个进程ID，用空格分隔</p><p>列出所有可用信号及其编号：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">kill</span> <span class="token parameter variable">-l</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><p>​<code>kill -9</code>​​：</p><ul><li>发送 <code>SIGKILL</code>​ 信号给目标进程，该信号是终止（kill）信号。</li><li>使用 <code>-9</code>​​ 选项会强制终止目标进程，进程将立即被终止，不会有清理操作或终止信号处理。</li><li>这种方式可能会导致进程在终止时无法进行资源释放或状态保存，可能会留下未处理的数据或文件。</li></ul></li><li><p>​<code>kill -15</code>​​：</p><ul><li>发送 <code>SIGTERM</code>​ 信号给目标进程，该信号是终止（terminate）信号。</li><li>使用 <code>-15</code>​​ 选项会优雅地请求目标进程终止，允许进程执行清理操作和终止信号处理。</li><li>这是一种通常建议的终止方法，因为它允许进程在退出前完成必要的操作。</li></ul></li><li><p>​<code>kill -20</code>​：</p><ul><li>发送 <code>SIGTSTP</code>​ 信号给目标进程，该信号是挂起（suspend）信号。</li><li>使用 <code>-20</code>​ 选项会暂停（挂起）目标进程，类似于按下 <code>Ctrl+Z</code>​ 键。进程会停止执行，但可以在后台继续运行。</li><li>适用于暂停正在运行的进程，然后将其放到后台以便执行其他操作，在后续需要时重新启动它。</li></ul></li></ul><h2 id="nohup" tabindex="-1"><a class="header-anchor" href="#nohup" aria-hidden="true">#</a> nohup</h2><p><strong>nohup</strong> 英文全称 no hang up（不挂起），用于在系统后台不挂断地运行命令，退出终端不会影响程序的运行。</p><p><strong>nohup</strong> 命令，在默认情况下（非重定向时），会输出一个名叫 nohup.out 的文件到当前目录下，如果当前目录的 nohup.out 文件不可写，输出重定向到 <strong>$HOME/nohup.out</strong> 文件中。</p><p>基本语法格式如下：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code> <span class="token function">nohup</span> Command <span class="token punctuation">[</span> Arg … <span class="token punctuation">]</span> <span class="token punctuation">[</span>　<span class="token operator">&amp;</span> <span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>Command</strong>：要执行的命令。</p><p><strong>Arg</strong>：一些参数，可以指定输出文件。</p><p><strong>&amp;</strong>：让命令在后台执行，终端退出后命令仍旧执行。</p><p>以下是一些常用的 <code>nohup</code>​ 命令选项以及案例说明：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">nohup</span> <span class="token function">sh</span> <span class="token parameter variable">-c</span> <span class="token string">&#39;while true; do date; sleep 2; done&#39;</span>  <span class="token operator">&gt;</span> log.txt <span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span><span class="token file-descriptor important">&amp;1</span> <span class="token operator">&amp;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>2&gt;&amp;1</strong> 解释：</p><p>将标准错误 2 重定向到标准输出 &amp;1 ，标准输出 &amp;1 再被重定向输入到 <code>log.txt</code>​ 文件中。</p><ul><li>0 – stdin (standard input，标准输入)</li><li>1 – stdout (standard output，标准输出)</li><li>2 – stderr (standard error，标准错误输出)</li></ul><h2 id="top" tabindex="-1"><a class="header-anchor" href="#top" aria-hidden="true">#</a> top</h2><p>​<code>top</code>​ 是一个命令行实用程序，用于实时监视系统的运行状态和进程活动。它可以显示各种系统性能指标，如CPU使用率、内存使用、进程列表等，并且会持续刷新显示，以便实时了解系统的性能情况。</p><p>常见的交互式操作：</p><ul><li>使用键盘上的箭头键上下浏览进程列表。</li><li>按下 <code>f</code>​键进入交互界面，使用 <code>d</code>​或<code>​ space</code>​选择是否显示某些字段，使用 <code>s</code>​ 指定字段排序</li><li>按下 <code>Shift+M</code>​ 按内存使用排序进程列表。</li><li>按下 <code>Shift+P</code>​ 按CPU使用排序进程列表。</li><li>按下 <code>k</code>​ 键输入进程PID来终止一个进程。</li><li>按下 <code>q</code>​ 键退出 <code>top</code>​。</li></ul><p>每一列字段说明：</p><ul><li>​<code>PID</code>​：进程ID，唯一标识一个进程。</li><li>​<code>USER</code>​：进程的所有者用户名。</li><li>​<code>PR</code>​：进程的优先级。</li><li>​<code>NI</code>​：NICE值，影响进程的调度优先级。</li><li>​<code>VIRT</code>​：进程使用的虚拟内存量。</li><li>​<code>RES</code>​：进程使用的实际物理内存量（Resident Set Size）。</li><li>​<code>SHR</code>​：进程使用的共享内存量。</li><li>​<code>S</code>​：进程状态，如运行（R）、等待（S）、停止（T）、僵尸（Z）等。</li><li>​<code>%CPU</code>​：进程使用的CPU资源百分比。</li><li>​<code>%MEM</code>​：进程使用的内存资源百分比。</li><li>​<code>TIME+</code>​：进程在CPU上的累计运行时间。</li><li>​<code>COMMAND</code>​：进程的命令行。</li></ul>`,36),i=[l];function c(p,d){return e(),n("div",null,i)}const u=s(o,[["render",c],["__file","进程管理命令.html.vue"]]);export{u as default};
